import type { DMMF } from '@prisma/generator-helper'

const PRISMA_SCALAR_TO_TS: Readonly<Record<string, string>> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  DateTime: 'Date',
  Json: 'unknown',
  BigInt: 'bigint',
  Bytes: 'Buffer',
  Decimal: 'number',
}

/** Maps a Prisma scalar type name to its TypeScript equivalent. Enum and relation type names pass through unchanged. */
export function prismaTypeToTs(type: string): string {
  return PRISMA_SCALAR_TO_TS[type] ?? type
}

/** Returns a TypeScript type annotation string for a field, accounting for list and nullability. */
export function fieldTypeAnnotation(field: DMMF.Field): string {
  const base = prismaTypeToTs(field.type)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/** Derives the REST resource path segment from a model name (lowercase + 's'). */
export function toResourcePath(modelName: string): string {
  return modelName.toLowerCase() + 's'
}

/** Returns the `@id` field for a model, or `undefined` if the model has no single-field primary key. */
export function idField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId)
}

function isWritableField(field: DMMF.Field): boolean {
  return field.kind !== 'object' && field.kind !== 'unsupported' && !field.isReadOnly && !field.isUpdatedAt
}

function isAutoGeneratedId(field: DMMF.Field): boolean {
  return field.isId && field.hasDefaultValue
}

/** Renders the TypeScript interface for the model, including all scalar and enum fields. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldTypeAnnotation(f)}`)
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}\n`
}

/** Renders the CreateInput interface: all writable fields, omitting auto-generated IDs and read-only timestamps. */
export function renderCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => isWritableField(f) && !isAutoGeneratedId(f))
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${fieldTypeAnnotation(f)}`)
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}\n`
}

/** Renders the UpdateInput interface: same field set as CreateInput but every field is optional. */
export function renderUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => isWritableField(f) && !isAutoGeneratedId(f))
    .map((f) => `  ${f.name}?: ${fieldTypeAnnotation(f)}`)
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}\n`
}

/**
 * Renders the CRUD method block for a model as a `RestClient` class property initializer.
 *
 * If the model has no `@id` field, `findUnique`, `update`, and `delete` fall back to
 * `id: unknown` so the output is still valid TypeScript.
 */
export function renderModelProperty(model: DMMF.Model): string {
  const resource = toResourcePath(model.name)
  const id = idField(model)
  const idType = id ? prismaTypeToTs(id.type) : 'unknown'
  const idParam = id?.name ?? 'id'
  const n = model.name
  const camelName = n.charAt(0).toLowerCase() + n.slice(1)

  return [
    `  readonly ${camelName} = {`,
    `    findMany: async (params?: { skip?: number; take?: number }): Promise<${n}[]> => {`,
    `      const url = new URL(\`\${this.baseUrl}/${resource}\`)`,
    `      if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))`,
    `      if (params?.take !== undefined) url.searchParams.set('take', String(params.take))`,
    `      const res = await fetch(url.toString())`,
    `      return res.json() as Promise<${n}[]>`,
    `    },`,
    `    findUnique: async (${idParam}: ${idType}): Promise<${n} | null> => {`,
    `      const res = await fetch(\`\${this.baseUrl}/${resource}/\${${idParam}}\`)`,
    `      if (res.status === 404) return null`,
    `      return res.json() as Promise<${n}>`,
    `    },`,
    `    create: async (data: ${n}CreateInput): Promise<${n}> => {`,
    `      const res = await fetch(\`\${this.baseUrl}/${resource}\`, {`,
    `        method: 'POST',`,
    `        headers: { 'Content-Type': 'application/json' },`,
    `        body: JSON.stringify(data),`,
    `      })`,
    `      return res.json() as Promise<${n}>`,
    `    },`,
    `    update: async (${idParam}: ${idType}, data: ${n}UpdateInput): Promise<${n}> => {`,
    `      const res = await fetch(\`\${this.baseUrl}/${resource}/\${${idParam}}\`, {`,
    `        method: 'PATCH',`,
    `        headers: { 'Content-Type': 'application/json' },`,
    `        body: JSON.stringify(data),`,
    `      })`,
    `      return res.json() as Promise<${n}>`,
    `    },`,
    `    delete: async (${idParam}: ${idType}): Promise<${n}> => {`,
    `      const res = await fetch(\`\${this.baseUrl}/${resource}/\${${idParam}}\`, { method: 'DELETE' })`,
    `      return res.json() as Promise<${n}>`,
    `    },`,
    `  }`,
  ].join('\n')
}

