import type { DMMF } from '@prisma/generator-helper'
import type { GeneratorOptions } from '@prisma/generator-helper'
import { promises as fs } from 'node:fs'
import * as path from 'node:path'

import { renderCreateInput, renderModelInterface, renderModelProperty, renderUpdateInput } from './template'

/** Runs the generator: writes `rest-client.ts` to the configured output directory. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('output directory is not configured; add `output = "..."` to the generator block')
  }

  await fs.mkdir(outputDir, { recursive: true })

  const { models } = options.dmmf.datamodel
  const content = buildFileContent(models)

  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

function buildFileContent(models: readonly DMMF.Model[]): string {
  const sections: string[] = [
    '// Auto-generated by @prisma/generator-rest-client. Do not edit manually.\n',
  ]

  for (const model of models) {
    sections.push(renderModelInterface(model))
    sections.push(renderCreateInput(model))
    sections.push(renderUpdateInput(model))
  }

  sections.push(buildClientClass(models))

  return sections.join('\n')
}

function buildClientClass(models: readonly DMMF.Model[]): string {
  const properties = models.map(renderModelProperty).join('\n\n')
  return ['export class RestClient {', '  constructor(private readonly baseUrl: string) {}', '', properties, '}'].join(
    '\n',
  )
}

